  "checklist": "[background:var(--card)] [border:1px_solid_var(--border)] [border-radius:var(--radius-lg)] [padding:14px] [display:grid] [gap:7px] [&_p]:[color:var(--muted)] [&_p]:[font-size:12px] [padding:var(--card-padding)] [&_p]:[font-size:var(--page-subtitle-size)]",
