  "statusText": "[color:var(--text)] [font-weight:700] [margin-top:4px]",
  "smallBtn": "[border-radius:var(--radius-md)] [background:var(--primary-dim)] [color:var(--primary)] [font-size:12px] [font-weight:700] [padding:8px_12px] [flex-shrink:0]",
  "inlineBtn": "[border-radius:var(--radius-md)] [background:var(--primary-dim)] [color:var(--primary)] [font-size:12px] [font-weight:700] [padding:7px_10px] [white-space:nowrap]",
  "hospitalHeader": "[display:flex] [align-items:center] [justify-content:space-between] [gap:12px] [&_h2]:[color:var(--text)] [&_h2]:[font-size:15px] [&_p]:[color:var(--muted)] [&_p]:[font-size:12px] [&_p]:[margin-top:2px] max-[560px]:[align-items:stretch] max-[560px]:[flex-direction:column]",
  "sosMap": "[width:100%] [min-height:220px] [border-radius:var(--radius-lg)] [overflow:hidden] [border:1px_solid_var(--border)] [margin-bottom:14px] [&_iframe]:[width:100%] [&_iframe]:[min-height:220px] [&_iframe]:[border:0]",
  "listState": "[background:var(--card)] [border:1px_dashed_var(--border)] [border-radius:var(--radius-lg)] [color:var(--muted)] [display:flex] [align-items:center] [justify-content:space-between] [gap:12px] [padding:16px] max-[560px]:[align-items:stretch] max-[560px]:[flex-direction:column] [padding:var(--card-padding)]",
  "hospitalList": "[display:flex] [flex-direction:column] [gap:10px]",
  "rank": "[width:30px] [height:30px] [border-radius:10px] [background:var(--accent-dim)] [color:var(--accent)] [display:flex] [align-items:center] [justify-content:center] [font-weight:800] [flex-shrink:0]",
  "hospitalMain": "[flex:1] [min-width:0] [&_h3]:[color:var(--text)] [&_h3]:[font-size:13px] [&_h3]:[font-weight:800] [&_p]:[color:var(--muted)] [&_p]:[font-size:12px] [&_p]:[margin-top:3px]",
  "hospitalActions": "[display:flex] [gap:8px] [flex-wrap:wrap] [margin-top:10px] [&_a]:[background:var(--card2)] [&_a]:[border:1px_solid_var(--border)] [&_a]:[border-radius:var(--radius-md)] [&_a]:[color:var(--text)] [&_a]:[font-size:11px] [&_a]:[font-weight:700] [&_a]:[padding:6px_9px] [&_a]:[min-height:var(--control-height)] [&_a]:[font-size:var(--control-font-size)]",
  "cancel": "[font-size:12px] [color:var(--subtle)] [background:none] [border:none] [cursor:pointer] [padding:8px_12px] [border-radius:var(--radius-md)] [transition:color_0.15s,_background_0.15s] [align-self:center] hover:[color:var(--muted)] hover:[background:var(--card2)] [min-height:var(--control-height)] [font-size:var(--control-font-size)]",
  "page": "[gap:var(--page-gap)]",
